1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: Item[];
10	}
11	
12	interface Damage {
13	  itemType: string;
14	  amount: number;
15	}
16	
17	interface Incident {
18	  cause: string;
19	  damages: Damage[];
20	}
21	
22	interface ClaimStep {
23	  op: "claim";
24	  policy: number;
25	  incident: Incident;
26	}
27	
28	type Step = QuoteStep | ClaimStep;
29	
30	interface Scenario {
31	  customer: { yearsWithMHPCO: number };
32	  steps: Step[];
33	}
34	
35	const BASE_PREMIUM: Record<string, number> = {
36	  sword: 100,
37	  amulet: 60,
38	  staff: 80,
39	  potion: 40,
40	};
41	
42	const COMPONENT_PREMIUM = 25;
43	const COMPONENT_BLOCK_SIZE = 3;
44	const COMPONENT_BLOCK_PREMIUM = 60;
45	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
46	
47	const INSURANCE_VALUE: Record<string, number> = {
48	  sword: 1000,
49	  amulet: 600,
50	  staff: 800,
51	  potion: 400,
52	};
53	const COMPONENT_INSURANCE_VALUE = 250;
54	
55	const DEDUCTIBLE = 100;
56	const CAP_MULTIPLIER = 2;
57	const HALF_REIMBURSEMENT_ENCHANTMENT = 8;
58	const HALF_REIMBURSEMENT_RATE = 0.5;
59	
60	const FIRST_INSURANCE_SURCHARGE = 1.1;
61	const CURSE_SURCHARGE_RATE = 0.5;
62	const HIGH_ENCHANTMENT_THRESHOLD = 5;
63	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
64	const LOYALTY_THRESHOLD_YEARS = 2;
65	const LOYALTY_DISCOUNT_RATE = 0.2;
66	const FOLLOWUP_DISCOUNT_RATE = 0.15;
67	const PROCESSING_FEE = 5;
68	
69	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
70	
71	const isKnownType = (type: string): boolean => type in BASE_PREMIUM || COMPONENT_TYPES.has(type);
72	
73	const sum = (values: number[]): number => values.reduce((acc, value) => acc + value, 0);
74	
75	// Base premium of a single item (main item or one component).
76	const itemBase = (item: Item): number =>
77	  isComponent(item) ? COMPONENT_PREMIUM : (BASE_PREMIUM[item.type] ?? 0);
78	
79	// A surcharge adds `rate` of the base premium for each affected item.
80	const surchargeFor = (items: Item[], affects: (item: Item) => boolean, rate: number): number =>
81	  sum(items.filter(affects).map((item) => rate * itemBase(item)));
82	
83	// Curse adds 50% of the affected item's base premium.
84	const curseSurcharge = (items: Item[]): number =>
85	  surchargeFor(items, (item) => item.cursed === true, CURSE_SURCHARGE_RATE);
86	
87	// High enchantment (level >= 5) adds 30% of the affected item's base premium.
88	const enchantmentSurcharge = (items: Item[]): number =>
89	  surchargeFor(
90	    items,
91	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
92	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
93	  );
94	
95	// Base premium for `count` alike components: a group of exactly 3 forms a
96	// block at COMPONENT_BLOCK_PREMIUM; otherwise each component costs
97	// COMPONENT_PREMIUM.
98	const componentGroupPremium = (count: number): number =>
99	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
100	
101	// Count how many alike components of each type appear (e.g. { rune: 2 }).
102	const countByType = (items: Item[]): Map<string, number> =>
103	  items.reduce((counts, item) => {
104	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
105	    return counts;
106	  }, new Map<string, number>());
107	
108	const mainItemsPremium = (items: Item[]): number =>
109	  sum(items.filter((item) => !isComponent(item)).map(itemBase));
110	
111	const componentsPremium = (items: Item[]): number =>
112	  sum([...countByType(items.filter(isComponent)).values()].map(componentGroupPremium));
113	
114	const basePremium = (items: Item[]): number =>
115	  mainItemsPremium(items) + componentsPremium(items);
116	
117	// Insurance value of a single item (main item or one component).
118	const insuranceValue = (item: Item): number =>
119	  isComponent(item) ? COMPONENT_INSURANCE_VALUE : (INSURANCE_VALUE[item.type] ?? 0);
120	
121	// Snap away floating-point noise (e.g. 197.5000000001) by rounding to 6
122	// decimal places, so a subsequent ceil/floor lands on the intended whole G.
123	const FLOAT_GUARD_PRECISION = 1e6;
124	const snapFloat = (value: number): number =>
125	  Math.round(value * FLOAT_GUARD_PRECISION) / FLOAT_GUARD_PRECISION;
126	
127	// Round up to a whole number in MHPCO's favour.
128	const roundUpToWhole = (value: number): number => Math.ceil(snapFloat(value));
129	
130	// Round a payout down to whole G, in MHPCO's favour.
131	const roundDownToWhole = (value: number): number => Math.floor(snapFloat(value));
132	
133	// A policy-wide discount takes `rate` of the policy base when it applies.
134	const discount = (applies: boolean, rate: number, base: number): number =>
135	  applies ? rate * base : 0;
136	
137	// Long-standing customers (>= 2 years) receive 20% off the policy base.
138	const loyaltyDiscount = (base: number, yearsWithMHPCO: number): number =>
139	  discount(yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, LOYALTY_DISCOUNT_RATE, base);
140	
141	// Every quote after the customer's first receives 15% off the policy base.
142	const followUpDiscount = (base: number, isFollowUp: boolean): number =>
143	  discount(isFollowUp, FOLLOWUP_DISCOUNT_RATE, base);
144	
145	// Premium for one quote: base premium plus the first-insurance surcharge,
146	// item-specific curse/enchantment surcharges, less the policy-wide loyalty
147	// and follow-up discounts, and the flat processing fee.
148	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFollowUp: boolean): number => {
149	  for (const item of items) {
150	    if (!isKnownType(item.type)) {
151	      throw new Error(`unknown item type: ${item.type}`);
152	    }
153	  }
154	  const base = basePremium(items);
155	  return (
156	    base * FIRST_INSURANCE_SURCHARGE +
157	    curseSurcharge(items) +
158	    enchantmentSurcharge(items) -
159	    loyaltyDiscount(base, yearsWithMHPCO) -
160	    followUpDiscount(base, isFollowUp) +
161	    PROCESSING_FEE
162	  );
163	};
164	
165	// Reimbursable amount for damage to one item: halved for highly enchanted
166	// items (>= 8), otherwise the full damage amount.
167	const reimbursement = (item: Item, amount: number): number =>
168	  (item.enchantment ?? 0) >= HALF_REIMBURSEMENT_ENCHANTMENT
169	    ? HALF_REIMBURSEMENT_RATE * amount
170	    : amount;
171	
172	// Payout for one damage event: reimbursement less the per-event deductible.
173	// A negative damage amount is invalid and rejected.
174	const damagePayout = (item: Item, damage: Damage): number => {
175	  if (damage.amount < 0) {
176	    throw new Error(`negative damage amount: ${damage.amount}`);
177	  }
178	  return Math.max(0, reimbursement(item, damage.amount) - DEDUCTIBLE);
179	};
180	
181	// Pair each damage with a distinct policy item of the same type, consuming that
182	// item so it can back only one damage. A damage with no remaining matching item
183	// (not insured, or more damages of a type than the policy covers) is rejected.
184	const pairDamagesWithItems = (policy: Item[], damages: Damage[]): [Item, Damage][] => {
185	  const available = [...policy];
186	  return damages.map((damage): [Item, Damage] => {
187	    const index = available.findIndex((item) => item.type === damage.itemType);
188	    if (index === -1) {
189	      throw new Error(`damaged item not in policy: ${damage.itemType}`);
190	    }
191	    const [item] = available.splice(index, 1);
192	    return [item, damage];
193	  });
194	};
195	
196	// Total cap for a policy: twice the sum of its items' insurance values.
197	const policyCap = (policy: Item[]): number => CAP_MULTIPLIER * sum(policy.map(insuranceValue));
198	
199	// Payout for a claim against a policy with `remainingCap` left: the desired
200	// reimbursement (per-damage, deductible applied) limited to the remaining cap.
201	const claimResult = (
202	  policy: Item[],
203	  incident: Incident,
204	  remainingCap: number,
205	): { payout: number; remainingCap: number } => {
206	  const pairs = pairDamagesWithItems(policy, incident.damages);
207	  const desired = roundDownToWhole(
208	    sum(pairs.map(([item, damage]) => damagePayout(item, damage))),
209	  );
210	  const payout = Math.min(desired, remainingCap);
211	  return { payout, remainingCap: remainingCap - payout };
212	};
213	
214	// What MHPCO remembers about each policy it has quoted: the insured items and
215	// how much of the claim cap is still available.
216	interface Policy {
217	  items: Item[];
218	  remainingCap: number;
219	}
220	
221	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
222	  const { yearsWithMHPCO } = scenario.customer;
223	  const policiesByStep: Record<number, Policy> = {};
224	  let quotesSeen = 0;
225	  const results = scenario.steps.map((step, index) => {
226	    if (step.op === "claim") {
227	      const policy = policiesByStep[step.policy];
228	      const result = claimResult(policy.items, step.incident, policy.remainingCap);
229	      policy.remainingCap = result.remainingCap;
230	      return result;
231	    }
232	    const isFollowUp = quotesSeen > 0;
233	    quotesSeen += 1;
234	    policiesByStep[index] = { items: step.items, remainingCap: policyCap(step.items) };
235	    return { premium: roundUpToWhole(quotePremium(step.items, yearsWithMHPCO, isFollowUp)) };
236	  });
237	  return { results };
238	};
